This is an obfuscated JavaScript snippet that runs a **2D Force-Directed Graph simulation with a particle system and smooth camera movement**. 

It is commonly used as a background animation on websites (often rendered onto an HTML `<canvas>`).

Here is the fully cleaned, deobfuscated code, followed by a detailed explanation of how it works.

### Deobfuscated Code

```javascript
// Mathematical constants
const TWO_PI = 6.283;
const PHI = 1.618;
const ROOT_HALF = 0.707; // Math.sin(Math.PI / 4)

// Simulation configuration
const config = {
    attraction: 4000,
    frictionCoeff: 0.004,
    amplification: 0.92,
    dispersal: 0.0003,
    streamMax: 40,
    streamDecay: 0.04,
    theta: 0.06 // Camera LERP factor
};

// Graph Nodes (Vertices)
const nodes = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Graph Edges (Springs connecting nodes)
const edges = [
    { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera variables
let currentCamera = { x: 400, y: 300, zoom: 1 };
let targetCamera  = { x: 400, y: 300, zoom: 1 };

// Particle system variables
let particles = [];
let tickCount = 0;

// Helper: Find a node by its string ID
function getNodeById(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// 1. Calculate physics for nodes and springs
function updatePhysics() {
    // A. N-Body Repulsion (Nodes push away from each other)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let distSq = (dx * dx + dy * dy) || 1;

            // Inverse square law for repulsion
            let force = config.attraction / distSq; 
            let dist = Math.sqrt(distSq);

            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            nodes[i].vx += fx; nodes[i].vy += fy;
            nodes[j].vx -= fx; nodes[j].vy -= fy;
        }
    }

    // B. Hooke's Law (Springs pull connected nodes to their 'rest' length)
    for (let i = 0; i < edges.length; i++) {
        let nodeA = getNodeById(edges[i].a);
        let nodeB = getNodeById(edges[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;

        let stretch = dist - edges[i].rest;
        let force = (edges[i].k) * stretch;

        let fx = (dx / dist) * force;
        let fy = (dy / dist) * force;

        nodeA.vx += fx; nodeA.vy += fy;
        nodeB.vx -= fx; nodeB.vy -= fy;
    }

    // C. Center Gravity & Velocity Application
    for (let i = 0; i < nodes.length; i++) {
        // Nodes are gently pulled toward the center (400, 300)
        nodes[i].vx += (400 - nodes[i].x) * config.dispersal;
        nodes[i].vy += (300 - nodes[i].y) * config.dispersal;

        // Apply friction/damping
        nodes[i].vx *= config.amplification;
        nodes[i].vy *= config.amplification;

        // Apply velocity to position
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}

// 2. Spawn visual particles from nodes
function spawnParticles() {
    if (particles.length >= config.streamMax) return;

    // Pick a random node to emit a particle
    let node = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * TWO_PI;
    let speed = 0.3 + (Math.random() * ROOT_HALF);

    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * PHI * ROOT_HALF)
    });
}

// 3. Update active particles
function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];

        // Decelerate particles over time
        p.vx *= (1 - config.streamDecay * 0.125);
        p.vy *= (1 - config.streamDecay * 0.125);

        // Move particle
        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        // Remove dead particles
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// 4. Smooth Camera movement
function updateCamera() {
    // Linear interpolation (LERP) towards target camera position
    currentCamera.x += (targetCamera.x - currentCamera.x) * config.theta;
    currentCamera.y += (targetCamera.y - currentCamera.y) * config.theta;
    currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * config.theta;
}

// 5. Main Game Loop
function mainLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Spawn particles every 3 frames
    if (tickCount % 3 === 0) spawnParticles();

    tickCount++;
}

// Run the loop every 16ms (~60 Frames Per Second)
setInterval(mainLoop, 16);
```

### Explanation of the Mechanics

1. **The Graph Setup:** 
   The code defines an array of interconnected nodes (`hub`, `alpha`, `beta`, etc.). There is a `hub` node in the center (size 26), surrounded by smaller satellite nodes. 
2. **The Physics Engine (Force-Directed Graph):** 
   This calculates realistic bouncy movement for the nodes using 3 rules:
   * **Repulsion:** All nodes act like magnets of the same polarity. They push away from one another based on an inverse-square calculation.
   * **Springs:** The `edges` connect specific nodes together. Hooke's law is applied to pull nodes together if they drift too far apart, or push them away if they get too close to each other.
   * **Center Gravity:** To prevent the nodes from drifting entirely off the screen, a tiny bit of gravity constantly pulls them toward `X: 400, Y: 300`.
3. **The Particle Engine:**
   Every 3 frames, the code selects a random node and spawns a "particle" from it. This particle shoots out at a random trajectory, slows down over time (friction), and eventually dies when it reaches its `maxAge`.
4. **The Camera:**
   A built-in camera uses **LERP** (Linear Interpolation). It slowly eases `currentCamera` toward `targetCamera`. While rendering logic isn't present in this snippet, an external script would read `currentCamera.x` and `currentCamera.zoom` to pan the canvas around.
5. **The Obfuscation:** 
   The original code used a very common JS packer that wraps string variables in a shifting Base64 decoder array, replaces standard math with object-wrapped functions (e.g., `_0x56c027['WrNaY'](a, b)` instead of `a - b`), and flattens out linear logic into `while/switch` loops controlled by a string like `"1|4|3|2|0"`.
